pub fn unsafe_get_tsp_tst_currentTemp() -> Option<TempControl_SysVerif::Temperature>
{
  unsafe {
    let value: *mut TempControl_SysVerif::Temperature = &mut TempControl_SysVerif::Temperature::default();
    if (get_tsp_tst_currentTemp(value)) {
      return Some(*value);
    } else {
      return None;
    }
  }
}

